query:
SELECT COUNT(*) as total FROM nameHistory;
SELECT nh.id, nh.userId, u.name as currentName, nh.oldName, nh.newName, nh.changedAt 
FROM nameHistory nh 
JOIN users u ON u.id = nh.userId 
ORDER BY nh.changedAt ASC 
LIMIT 10;

